code.C:
#include <stdio.h>

int main() {
    int number, digit1, digit2, digit3;
    scanf("%d", &number);
    digit1 = number % 10;
    digit2 = (number / 10) % 10;
    digit3 = number / 100;
    printf("Digits in reverse order: %d %d %d\n", digit1, digit2, digit3);
    return 0;
}

