code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
readline.question('', (number) => {
    let digit1 = parseInt(number) % 10;
    let digit2 = Math.floor(parseInt(number) / 10) % 10;
    let digit3 = Math.floor(parseInt(number) / 100);
    console.log(`Digits in reverse order: ${digit1} ${digit2} ${digit3}`);
    readline.close();
});
